import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { CartContext } from '../context/CartContext';
import { Trash2 } from 'lucide-react';

const BASE_URL = 'http://localhost:5000';

const Cart = () => {
  const { cartItems, removeFromCart, updateQuantity, cartTotal } = useContext(CartContext);

  return (
    <div className="container">
      <h1 className="page-title">Your Cart</h1>

      {cartItems.length === 0 ? (
        <p style={{ textAlign: 'center' }}>Your cart is empty. <Link to="/shop" style={{ textDecoration: 'underline' }}>Continue shopping.</Link></p>
      ) : (
        <>
          <table className="cart-table">
            <thead>
              <tr>
                <th style={{ width: '60px' }}></th>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Total</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {cartItems.map((item) => (
                <tr key={item._id}>
                  <td>
                    <div style={{
                      width: '50px', height: '50px', backgroundImage: item.imageUrl ? `url(${BASE_URL}${item.imageUrl})` : 'none',
                      backgroundSize: 'cover', backgroundPosition: 'center', backgroundColor: 'var(--color-gray-light)',
                    }}></div>
                  </td>
                  <td>{item.name}</td>
                  <td>${item.price}</td>
                  <td>
                    <div style={{ display: 'flex', border: '1px solid var(--color-border)', width: 'fit-content' }}>
                      <button
                        onClick={() => updateQuantity(item._id, item.quantity - 1)}
                        disabled={item.quantity <= 1}
                        style={{
                          width: '30px', height: '30px', border: 'none', background: 'var(--color-gray-light)',
                          cursor: 'pointer', fontSize: '1rem',
                        }}
                      >−</button>
                      <span style={{
                        width: '35px', height: '30px', display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: '0.85rem', fontWeight: 500,
                      }}>{item.quantity}</span>
                      <button
                        onClick={() => updateQuantity(item._id, item.quantity + 1)}
                        style={{
                          width: '30px', height: '30px', border: 'none', background: 'var(--color-gray-light)',
                          cursor: 'pointer', fontSize: '1rem',
                        }}
                      >+</button>
                    </div>
                  </td>
                  <td>${item.price * item.quantity}</td>
                  <td>
                    <button onClick={() => removeFromCart(item._id)} style={{ color: '#dc2626', cursor: 'pointer', border: 'none', background: 'none' }}>
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="cart-summary">
            <div className="cart-summary-row">
              <span>Subtotal</span>
              <span>${cartTotal}</span>
            </div>
            <div className="cart-summary-row">
              <span>Shipping</span>
              <span>Complimentary</span>
            </div>
            <div className="cart-summary-row cart-summary-total">
              <span>Total</span>
              <span>${cartTotal}</span>
            </div>
            <button className="btn" style={{ width: '100%', marginTop: '20px' }}>Checkout</button>
          </div>
        </>
      )}
    </div>
  );
};

export default Cart;
